#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

// Returns (F_n, F_{n+1}) modulo MOD using fast doubling
void fib(int64_t n, int64_t *fn, int64_t *fn1) {
    if (n == 0) {
        *fn = 0;
        *fn1 = 1;
        return;
    }
    int64_t a, b;
    fib(n >> 1, &a, &b); // a = F_m, b = F_{m+1}, m = n/2
    int64_t c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD; // F_{2m}
    int64_t d = ((a * a) % MOD + (b * b) % MOD) % MOD;       // F_{2m+1}
    if ((n & 1) == 0) {
        *fn = c;
        *fn1 = d;
    } else {
        *fn = d;
        *fn1 = (c + d) % MOD;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        int64_t fn, fn1;
        // answer is F_{N+1}
        fib(N + 1, &fn, &fn1);
        printf("%lld\n", fn);
    }
    return 0;
}

