#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;

pair<long long,long long> fib(long long n) {
    if (n == 0) return {0, 1};
    auto p = fib(n >> 1);
    long long a = p.first;   // F_m
    long long b = p.second;  // F_{m+1}
    long long c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD; // F_{2m}
    long long d = ((a * a) % MOD + (b * b) % MOD) % MOD;       // F_{2m+1}
    if ((n & 1) == 0) return {c, d};
    else return {d, (c + d) % MOD};
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin >> T)) return 0;
    while (T--) {
        long long N; 
        cin >> N;
        cout << fib(N + 1).first << '\n';
    }
    return 0;
}

