import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;
    static long[] fib(long n) {
        if (n == 0) return new long[]{0L, 1L};
        long[] p = fib(n >> 1);
        long a = p[0]; // F_m
        long b = p[1]; // F_{m+1}
        long c = (a * ((2L * b % MOD - a + MOD) % MOD)) % MOD; // F_{2m}
        long d = ((a * a) % MOD + (b * b) % MOD) % MOD;       // F_{2m+1}
        if ((n & 1L) == 0) return new long[]{c, d};
        else return new long[]{d, (c + d) % MOD};
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            long N = Long.parseLong(br.readLine().trim());
            sb.append(fib(N + 1)[0]).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys
MOD = 1000000007

def fib(n):
    if n == 0:
        return (0, 1)
    a, b = fib(n >> 1)  # a = F_m, b = F_{m+1}
    c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD  # F_{2m}
    d = (a * a + b * b) % MOD                       # F_{2m+1}
    if n & 1:
        return (d, (c + d) % MOD)
    else:
        return (c, d)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        n = int(data[i])
        out.append(str(fib(n + 1)[0]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

